    'richlist-received': { title: workerText(lang, 'richlist_received', 'Richlist Received'), subtitle: workerText(lang, 'richlist_received_subtitle', 'Top addresses by cumulative received value') },
    'richlist-wealth': { title: workerText(lang, 'wealth_distribution', 'Wealth Distribution'), subtitle: workerText(lang, 'wealth_distribution_subtitle', 'Holder and balance distribution by tier') },
    'profile-rank': { title: workerText(lang, 'profile_rankings', 'Profile Rankings'), subtitle: workerText(lang, 'profile_rankings_subtitle', 'Rank snapshot by profile') },
    'post-rank': { title: workerText(lang, 'post_rankings', 'Post Rankings'), subtitle: workerText(lang, 'post_rankings_subtitle', 'Rank snapshot by post') },
